package com.clashcoach.player;
import com.clashcoach.user.User; import javax.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="players") public class Player {
 @Id private UUID id; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="user_id", nullable=false) private User user; @Column(name="player_tag", nullable=false, unique=true) private String playerTag; @Column(name="player_name", nullable=false) private String playerName; @Column(name="town_hall_level", nullable=false) private int townHallLevel; @Column(name="last_successful_refresh_at", nullable=false) private Instant lastSuccessfulRefreshAt; @Column(name="created_at", nullable=false) private Instant createdAt; @Column(name="updated_at", nullable=false) private Instant updatedAt;
 protected Player() { } public Player(User user, String tag, PlayerData data) { id=UUID.randomUUID(); this.user=user; playerTag=tag; update(data); createdAt=Instant.now(); } public void update(PlayerData data) { playerName=data.getName(); townHallLevel=data.getTownHallLevel(); lastSuccessfulRefreshAt=Instant.now(); updatedAt=lastSuccessfulRefreshAt; } public UUID getId(){return id;} public User getUser(){return user;} public String getPlayerTag(){return playerTag;} public String getPlayerName(){return playerName;} public int getTownHallLevel(){return townHallLevel;} public Instant getLastSuccessfulRefreshAt(){return lastSuccessfulRefreshAt;}
}
